awk -F'\t' '
{
  path = $2
  bytes = $1
  # Skip directory entries themselves
  if (path == "/var/data" || path == "/var/data/logs" || path == "/var/data/backups" || path == "/var/data/cache" || path == "/var/data/cache/thumbnails" || path == "/var/data/uploads" || path == "/var/data/archives") next

  # Extract immediate subdirectory of /var/data
  # Path format: /var/data/SUBDIR/...
  if (match(path, /^\/var\/data\/([^\/]+)/, arr)) {
    subdir = arr[1]
    totals[subdir] += bytes
    grand_total += bytes
  }
}
END {
  for (dir in totals) {
    pct = (totals[dir] / grand_total) * 100
    printf "%s %d %.1f\n", dir, totals[dir], pct
  }
}' /home/user/disk_inventory.txt | sort -t' ' -k2,2nr | awk '{printf "%s %s %s%%\n", $1, $2, $3}' > /home/user/reports/directory_rollup.txt
